import{join}from"./path.js";const types=["peerDependencies","devDependencies","optionalDependencies","dependencies"];export function createWorkspaceGraph(e,n,t,o){const s=new Map,c=new Map;for(const e of o.values())e.pkgName&&c.set(e.pkgName,e);const p=e=>{const n=new Set;for(const o of types)if(e.manifest[o])for(const s in e.manifest[o])if(t.has(s)){const e=c.get(s);e&&n.add(e.dir)}return n};for(const t of n){const n=o.get(t);n&&s.set(join(e,t),p(n))}return s}